const configPage = $node['Lire paramètres'].json.results?.[0];
if (!configPage) throw new Error('Aucune configuration active trouvée dans Notion.');
const p = configPage.properties;
const config = {
  personnes: p['Personnes']?.number ?? 2,
  objectif: p['Objectif']?.select?.name ?? 'Perte de poids',
  calories: p['Calories cibles']?.number ?? 2200,
  budget: p['Budget hebdomadaire']?.number ?? 90,
  email: p['Email']?.email ?? 'jasonmarmignon@gmail.com',
  nouvelles_recettes_max: p['Nouvelles recettes max']?.number ?? 1,
  saison: p['Saison']?.select?.name ?? 'Automatique',
  jours: (p['Jours de cuisine']?.multi_select ?? []).map(x => x.name)
};
const recipes = ($json.results ?? []).map(page => {
  const r = page.properties;
  return {
    id: page.id,
    nom: r['Nom']?.title?.map(x => x.plain_text).join('') ?? '',
    type: r['Type']?.select?.name ?? '',
    saisons: (r['Saison']?.multi_select ?? []).map(x => x.name),
    calories: r['Calories par portion']?.number ?? null,
    proteines: r['Protéines (g)']?.number ?? null,
    note: r['Note']?.number ?? null,
    portions: r['Portions']?.number ?? 2,
    ingredients: r['Ingrédients']?.rich_text?.map(x => x.plain_text).join('') ?? '',
    preparation: r['Préparation']?.rich_text?.map(x => x.plain_text).join('') ?? ''
  };
}).filter(r => r.nom);
if (!recipes.length) throw new Error('Aucune recette validée trouvée dans Notion.');
const system = `Tu es le chef personnel de Jason. Compose un menu hebdomadaire simple et adapté à une perte de poids. Utilise uniquement les recettes existantes fournies. Évite poisson, quinoa, brocoli, épinards et choux de Bruxelles. Retourne uniquement le JSON demandé.`;
const user = `CONFIGURATION\n${JSON.stringify(config, null, 2)}\n\nRECETTES VALIDÉES\n${JSON.stringify(recipes, null, 2)}\n\nCrée un repas pour chaque jour configuré. Le nom de chaque recette doit correspondre exactement à un nom fourni. Fusionne les ingrédients dans une liste de courses classée par rayon.`;
return [{ json: { config, recipes, openai_body: {
  model: 'gpt-5-mini',
  input: [
    { role: 'system', content: [{ type: 'input_text', text: system }] },
    { role: 'user', content: [{ type: 'input_text', text: user }] }
  ],
  text: { format: {
    type: 'json_schema', name: 'weekly_menu', strict: true,
    schema: {
      type: 'object', additionalProperties: false,
      required: ['week_start','summary','meals','shopping','estimated_weekly_budget_eur','notes'],
      properties: {
        week_start: { type: 'string' }, summary: { type: 'string' },
        meals: { type: 'array', items: { type: 'object', additionalProperties: false, required: ['day','recipe_name','is_new','reason'], properties: { day:{type:'string'}, recipe_name:{type:'string'}, is_new:{type:'boolean'}, reason:{type:'string'} } } },
        shopping: { type: 'object', additionalProperties: false, required: ['fruits_legumes','viandes_proteines','produits_frais','epicerie','surgeles','autres'], properties: { fruits_legumes:{type:'array',items:{type:'string'}}, viandes_proteines:{type:'array',items:{type:'string'}}, produits_frais:{type:'array',items:{type:'string'}}, epicerie:{type:'array',items:{type:'string'}}, surgeles:{type:'array',items:{type:'string'}}, autres:{type:'array',items:{type:'string'}} } },
        estimated_weekly_budget_eur: { type: 'number' }, notes: { type: 'array', items: { type: 'string' } }
      }
    }
  } }
} } }];

const raw = $json.output_text ?? $json.output?.flatMap(o => o.content ?? []).find(c => c.type === 'output_text')?.text;
if (!raw) throw new Error('OpenAI n’a retourné aucun texte exploitable.');
let menu;
try { menu = JSON.parse(raw); } catch (e) { throw new Error('La réponse OpenAI n’est pas un JSON valide : ' + raw); }
const source = $node['Préparer la demande'].json;
const recipesByName = Object.fromEntries(source.recipes.map(r => [r.nom.trim().toLowerCase(), r]));
const dayMap = {lundi:'Lundi',mardi:'Mardi',mercredi:'Mercredi',jeudi:'Jeudi',vendredi:'Vendredi',samedi:'Samedi',dimanche:'Dimanche'};
const relations = {};
for (const meal of menu.meals ?? []) {
  const day = dayMap[String(meal.day).trim().toLowerCase()];
  const recipe = recipesByName[String(meal.recipe_name).trim().toLowerCase()];
  if (!day) throw new Error(`Jour inconnu retourné par OpenAI : ${meal.day}`);
  if (!recipe) throw new Error(`Recette inconnue retournée par OpenAI : ${meal.recipe_name}`);
  relations[day] = [{ id: recipe.id }];
}
const weekStart = menu.week_start;
const title = `Semaine du ${weekStart}`;
const mealLines = (menu.meals ?? []).map(m => `${m.day} — ${m.recipe_name}`).join('\n');
const notes = (menu.notes ?? []).join('\n');
const comment = [menu.summary, `Budget estimé : ${menu.estimated_weekly_budget_eur} €`, notes].filter(Boolean).join('\n');
const rich = (text) => [{ type: 'text', text: { content: String(text).slice(0, 2000) } }];
const menuBody = {
  parent: { type: 'data_source_id', data_source_id: '90d87eaa-a8c2-4160-b924-29944f841f2f' },
  icon: { type: 'emoji', emoji: '📅' },
  properties: {
    'Semaine': { type: 'title', title: rich(title) },
    'Date de début': { type: 'date', date: { start: weekStart } },
    'Statut': { type: 'select', select: { name: 'À vérifier' } },
    'Généré automatiquement': { type: 'checkbox', checkbox: true },
    'Commentaire': { type: 'rich_text', rich_text: rich(comment) },
    ...Object.fromEntries(Object.entries(relations).map(([day, relation]) => [day, { type: 'relation', relation }]))
  },
  children: [
    { object: 'block', type: 'heading_2', heading_2: { rich_text: rich('Menu de la semaine') } },
    ...mealLines.split('\n').map(line => ({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: rich(line) } })),
    { object: 'block', type: 'paragraph', paragraph: { rich_text: rich(menu.summary ?? '') } }
  ]
};
return [{ json: { menu, config: source.config, menu_page_body: menuBody } }];

const createdMenu = $json;
const payload = $node['Préparer la page Menu'].json;
const menu = payload.menu;
const config = payload.config;
const rich = (text) => [{ type: 'text', text: { content: String(text || '').slice(0, 2000) } }];
const list = (arr) => (arr ?? []).map(x => `• ${x}`).join('\n');
const coursesBody = {
  parent: { type: 'data_source_id', data_source_id: '1d5a2002-5d88-464c-a6bb-fc483c6edd35' },
  icon: { type: 'emoji', emoji: '🛒' },
  properties: {
    'Semaine': { type: 'title', title: rich(`Courses — semaine du ${menu.week_start}`) },
    'Date des courses': { type: 'date', date: { start: menu.week_start } },
    'Statut': { type: 'select', select: { name: 'À acheter' } },
    'Courses terminées': { type: 'checkbox', checkbox: false },
    'Menu lié': { type: 'relation', relation: [{ id: createdMenu.id }] },
    'Fruits et légumes': { type: 'rich_text', rich_text: rich(list(menu.shopping?.fruits_legumes)) },
    'Viandes et protéines': { type: 'rich_text', rich_text: rich(list(menu.shopping?.viandes_proteines)) },
    'Produits frais': { type: 'rich_text', rich_text: rich(list(menu.shopping?.produits_frais)) },
    'Épicerie': { type: 'rich_text', rich_text: rich(list(menu.shopping?.epicerie)) },
    'Surgelés': { type: 'rich_text', rich_text: rich(list(menu.shopping?.surgeles)) },
    'Autres': { type: 'rich_text', rich_text: rich(list(menu.shopping?.autres)) }
  },
  children: [
    { object: 'block', type: 'heading_2', heading_2: { rich_text: rich('Liste de courses') } },
    ...Object.entries(menu.shopping ?? {}).flatMap(([rayon, items]) => [
      { object: 'block', type: 'heading_3', heading_3: { rich_text: rich(rayon.replaceAll('_',' ')) } },
      ...(items ?? []).map(item => ({ object: 'block', type: 'to_do', to_do: { rich_text: rich(item), checked: false } }))
    ])
  ]
};
const menuUrl = createdMenu.url;
const lines = (menu.meals ?? []).map(m => `<li><strong>${m.day}</strong> : ${m.recipe_name}</li>`).join('');
const shoppingSections = Object.entries(menu.shopping ?? {}).map(([k,v]) => `<h3>${k.replaceAll('_',' ')}</h3><ul>${(v ?? []).map(i => `<li>${i}</li>`).join('')}</ul>`).join('');
const emailHtml = `<h2>🍽️ Menu de la semaine du ${menu.week_start}</h2><p>${menu.summary ?? ''}</p><ul>${lines}</ul><h2>🛒 Liste de courses</h2>${shoppingSections}<p><strong>Budget estimé :</strong> ${menu.estimated_weekly_budget_eur} €</p><p><a href="${menuUrl}">Ouvrir le menu dans Notion</a></p>`;
return [{ json: { courses_page_body: coursesBody, email_to: config.email, email_subject: `🍽️ Menu de la semaine du ${menu.week_start}`, email_html: emailHtml, menu_url: menuUrl, menu } }];

const prepared = $node['Préparer courses et email'].json;
const courses = $json;
return [{ json: { to: prepared.email_to, subject: prepared.email_subject, html: prepared.email_html + `<p><a href="${courses.url}">Ouvrir la liste de courses dans Notion</a></p>`, menu_url: prepared.menu_url, courses_url: courses.url } }];
